import { useState } from 'react';
import { View, Text, StyleSheet } from 'react-native';
import { CameraView, useCameraPermissions, type BarcodeScanningResult } from 'expo-camera';
import { SafeAreaView } from 'react-native-safe-area-context';
import { useQRScanner } from '@/hooks/useQRScanner';
import { ScanOverlay } from '@/components/scanner/ScanOverlay';
import { ScanResult } from '@/components/scanner/ScanResult';
import { FlashButton } from '@/components/scanner/FlashButton';
import { Button } from '@/components/ui/Button';
import theme from '@/theme';

export default function ScanScreen() {
  const [permission, requestPermission] = useCameraPermissions();
  const { isProcessing, scanResult, handleBarCodeScanned, resetScan, flash, toggleFlash } = useQRScanner();

  if (!permission) {
    return <View style={styles.container} />;
  }

  if (!permission.granted) {
    return (
      <SafeAreaView style={styles.permissionContainer}>
        <Text style={styles.permissionEmoji}>📷</Text>
        <Text style={styles.permissionTitle}>Acces a la camera</Text>
        <Text style={styles.permissionText}>
          AstroLab a besoin d'acceder a votre camera pour scanner les QR codes en magasin.
        </Text>
        <Button title="Autoriser la camera" onPress={requestPermission} />
      </SafeAreaView>
    );
  }

  const onBarcodeScanned = isProcessing
    ? undefined
    : (result: BarcodeScanningResult) => handleBarCodeScanned(result.data);

  return (
    <View style={styles.container}>
      <CameraView
        style={StyleSheet.absoluteFillObject}
        facing="back"
        enableTorch={flash}
        barcodeScannerSettings={{ barcodeTypes: ['qr'] }}
        onBarcodeScanned={onBarcodeScanned}
      />

      <ScanOverlay />

      {/* Top controls */}
      <SafeAreaView style={styles.topControls}>
        <Text style={styles.scanTitle}>Scanner un QR code</Text>
        <FlashButton enabled={flash} onToggle={toggleFlash} />
      </SafeAreaView>

      {/* Instruction */}
      <View style={styles.instruction}>
        <Text style={styles.instructionText}>
          Placez le QR code du commercant dans le cadre
        </Text>
      </View>

      {/* Result */}
      {scanResult && (
        <ScanResult
          success={scanResult.success}
          data={scanResult.data}
          error={scanResult.error}
          onScanAgain={resetScan}
          onDismiss={resetScan}
        />
      )}
    </View>
  );
}

const styles = StyleSheet.create({
  container: {
    flex: 1,
    backgroundColor: '#000',
  },
  permissionContainer: {
    flex: 1,
    justifyContent: 'center',
    alignItems: 'center',
    padding: theme.spacing.xl,
    backgroundColor: theme.colors.background,
  },
  permissionEmoji: {
    fontSize: 80,
    marginBottom: theme.spacing.lg,
  },
  permissionTitle: {
    fontSize: theme.fontSize['2xl'],
    fontWeight: '700',
    color: theme.colors.text,
    marginBottom: theme.spacing.sm,
  },
  permissionText: {
    fontSize: theme.fontSize.base,
    color: theme.colors.textMuted,
    textAlign: 'center',
    lineHeight: 22,
    marginBottom: theme.spacing.xl,
  },
  topControls: {
    position: 'absolute',
    top: 0,
    left: 0,
    right: 0,
    flexDirection: 'row',
    justifyContent: 'space-between',
    alignItems: 'center',
    paddingHorizontal: theme.spacing.lg,
    paddingTop: theme.spacing.md,
  },
  scanTitle: {
    fontSize: theme.fontSize.lg,
    fontWeight: '600',
    color: '#fff',
  },
  instruction: {
    position: 'absolute',
    bottom: 120,
    left: 0,
    right: 0,
    alignItems: 'center',
  },
  instructionText: {
    color: '#fff',
    fontSize: theme.fontSize.sm,
    backgroundColor: 'rgba(0,0,0,0.6)',
    paddingHorizontal: theme.spacing.md,
    paddingVertical: theme.spacing.sm,
    borderRadius: theme.borderRadius.full,
    overflow: 'hidden',
  },
});
